function TeamImage({ member }) {
  const [failed, setFailed] = React.useState(false);
  const initials = member.name.split(" ").map((part) => part[0]).join("").slice(0, 2);
  const objectPosition = member.name.includes("Jan") ? "50% 22%" : member.name.includes("Philip") ? "50% 28%" : member.name === "Akaya" ? "50% 40%" : "50% 27%";
  if (failed) return <div className="flex h-full w-full items-center justify-center bg-[#2F352F] text-3xl font-semibold text-[#F3EEDB]/70">{initials}</div>;
  return <img src={member.img} alt={member.name} onError={() => setFailed(true)} className="h-full w-full object-cover transition duration-[1400ms] group-hover:scale-110" style={{ objectPosition, filter: "contrast(1.06) saturate(1.04) brightness(1.03)" }} />;
}

function OptionButton({ active, children, onClick }) {
  return <button type="button" onClick={onClick} className="rounded-2xl border px-5 py-4 text-left text-sm font-medium transition hover:-translate-y-1 hover:shadow-lg" style={{ borderColor: active ? colors.red : colors.border, backgroundColor: active ? "#FFF1EE" : colors.surface }}>{children}</button>;
}

